  methods: {
    getFormattedDate() {
      const today = new Date();
      const year = today.getFullYear();
      const month = String(today.getMonth() + 1).padStart(2, '0');
      const day = String(today.getDate()).padStart(2, '0');
      return `${year}-${month}-${day}`;
    },
    parseProcedimiento() {
      if (!this.procedimientoText.trim()) {
        this.showStatus(' Por favor ingresa la descripción del procedimiento', 'error');
        return;
      }
      try {
        const lines = this.procedimientoText.split('\n').filter(line => line.trim() !== '');
        const table = [];
        let stepNumber = 1; // Nivel principal (5.1, 5.2, etc.)
        let subStepNumber = 0; // Para subniveles (5.1.1, 5.1.2, etc.)
        let currentMainStep = null; // Para rastrear el paso principal actual

        for (let i = 0; i < lines.length; i++) {
          const line = lines[i].trim();
          if (line === '') continue;

          // Detectar inicio de subsecciones (patrones como "5.1.1", "a)", "•", "-")
          if (this.isSubsectionStarter(line)) {
            if (currentMainStep) {
              subStepNumber++;
              const fullNumber = `${currentMainStep}.${subStepNumber}`;
              const responsible = this.extractResponsible(line);
              const activity = this.extractActivity(line, responsible);
              table.push({
                number: fullNumber,
                who: responsible,
                activity: activity,
                level: 'sub' // Marcar como subsección
              });
            } else {
              // Si no hay paso principal, tratar como paso normal
              const responsible = this.extractResponsible(line);
              const activity = this.extractActivity(line, responsible);
              table.push({
                number: `${stepNumber}`,
                who: responsible,
                activity: activity
              });
              stepNumber++;
              subStepNumber = 0; // Reiniciar contador de subsecciones
            }
          }
          // Detectar secciones principales
          else if (this.isMainProcessLine(line)) {
            table.push({
              number: '',
              who: '',
              activity: line,
              level: 'section'
            });
            currentMainStep = null; // Resetear paso principal
            subStepNumber = 0;
          }
          // Detectar preguntas de decisión
          else if (line.startsWith('¿')) {
            table.push({
              number: '',
              who: '',
              activity: line,
              level: 'question'
            });
            currentMainStep = null;
            subStepNumber = 0;
          }
          // Detectar alternativas (Si/No)
          else if (line.toLowerCase().startsWith('si ') || line.toLowerCase().startsWith('no ') || line.toLowerCase().startsWith('si,') || line.toLowerCase().startsWith('no,')) {
            table.push({
              number: '',
              who: '',
              activity: line,
              level: 'alternative'
            });
            currentMainStep = null;
            subStepNumber = 0;
          }
          // Detectar fin del proceso
          else if (line.toLowerCase().includes('fin del proceso')) {
            table.push({
              number: '',
              who: '',
              activity: 'Fin del Proceso',
              level: 'end'
            });
            currentMainStep = null;
            subStepNumber = 0;
          }
          // Procesar líneas normales con responsables
          else {
            const responsible = this.extractResponsible(line);
            const activity = this.extractActivity(line, responsible);
            if (responsible || activity) {
              table.push({
                number: `${stepNumber}`,
                who: responsible,
                activity: activity
              });
              currentMainStep = stepNumber; // Establecer como paso principal actual
              stepNumber++;
              subStepNumber = 0; // Reiniciar contador de subsecciones
            }
          }
        }
        this.generatedTable = table;
        this.showStatus(' Tabla generada automáticamente desde la descripción', 'success');
      } catch (error) {
        this.showStatus(' Error al procesar la descripción: ' + error.message, 'error');
      }
    },
    // Nuevo método para detectar inicios de subsecciones
    isSubsectionStarter(line) {
      const subsectionPatterns = [/^\d+\.\d+\.\d+/,
      // 5.1.1, 5.1.2, etc.
      /^[a-z]\)/,
      // a), b), c), etc.
      /^[ivx]+\)/,
      // i), ii), iii), etc.
      /^•\s/,
      // • elemento
      /^-\s/,
      // - elemento
      /^→\s/,
      // → elemento
      /^subpaso\s\d+/i,
      // subpaso 1, subpaso 2, etc.
      /^detalle\s\d+/i // detalle 1, detalle 2, etc.
      ];
      return subsectionPatterns.some(pattern => pattern.test(line.toLowerCase()));
    },
    isMainProcessLine(line) {
      // Una línea es un proceso principal si:
      // - No es una pregunta
      // - No es una alternativa (Si/No)
      // - No menciona un responsable específico al inicio
      // - Describe un proceso completo
      // - No contiene "fin del proceso"
      // - No es una subsección
      return !line.startsWith('¿') && !line.toLowerCase().startsWith('si ') && !line.toLowerCase().startsWith('no ') && !line.toLowerCase().startsWith('si,') && !line.toLowerCase().startsWith('no,') && !line.toLowerCase().includes('fin del proceso') && !this.extractResponsible(line) && !this.isSubsectionStarter(line) && line.length > 10; // Para evitar que líneas cortas se consideren secciones principales
    },
    extractResponsible(line) {
      // Patrones comunes para detectar responsables
      const patterns = [/^el (\w+)/i, /^la (\w+)/i, /^los (\w+)/i, /^las (\w+)/i, /^un (\w+)/i, /^una (\w+)/i, /^(\w+) (revisa|envía|realiza|verifica|corrige|aprueba|autoriza)/i];
      for (const pattern of patterns) {
        const match = line.match(pattern);
        if (match) {
          return this.capitalizeFirstLetter(match[1] || match[2]);
        }
      }
      return '';
    },
    extractActivity(line, responsible) {
      if (!responsible) return line;

      // Remover el responsable del inicio de la línea para obtener solo la actividad
      const patterns = [new RegExp(`^el ${responsible.toLowerCase()}\\s+`, 'i'), new RegExp(`^la ${responsible.toLowerCase()}\\s+`, 'i'), new RegExp(`^los ${responsible.toLowerCase()}\\s+`, 'i'), new RegExp(`^las ${responsible.toLowerCase()}\\s+`, 'i'), new RegExp(`^${responsible.toLowerCase()}\\s+`, 'i')];
      let activity = line;
      for (const pattern of patterns) {
        activity = activity.replace(pattern, '');
      }
      return activity.charAt(0).toUpperCase() + activity.slice(1);
    },
    capitalizeFirstLetter(string) {
      return string.charAt(0).toUpperCase() + string.slice(1);
    },
    loadExampleProcedimiento() {
